$path = 'D:\astro_py\astro_hub\src\web\base.html'
$raw = [System.IO.File]::ReadAllText($path)
$bytes = [System.Text.Encoding]::UTF8.GetBytes($raw)

# Find 'bWndFull' in the bytes
$target = [System.Text.Encoding]::UTF8.GetBytes('bWndFull')
$idx = -1
for ($i = 0; $i -le ($bytes.Length - $target.Length); $i++) {
    $match = $true
    for ($j = 0; $j -lt $target.Length; $j++) {
        if ($bytes[$i + $j] -ne $target[$j]) { $match = $false; break }
    }
    if ($match) { $idx = $i; break }
}

if ($idx -lt 0) { Write-Output "bWndFull not found"; exit 1 }

# Show 100 bytes before bWndFull
$start = [Math]::Max(0, $idx - 30)
$snippet = $bytes[$start..($idx + 50)]
Write-Output "Context around bWndFull (starting at byte $start):"
Write-Output ([System.Text.Encoding]::UTF8.GetString($snippet))
Write-Output ""
Write-Output "Raw bytes around match:"
for ($i = [Math]::Max(0, $idx - 20); $i -lt [Math]::Min($bytes.Length, $idx + 60); $i++) {
    Write-Output "byte[$i] = $($bytes[$i]) = $([char]$bytes[$i])"
}

